26	    username: 'sysadmin',
27	    passwordHash: hashAdmin.hash,
28	    salt: hashAdmin.salt,
29	    role: 'SystemAdministrator',
30	    failedAttempts: 0
31	  });
32	  const attId = await db.users.add({
33	    username: 'attendant',
34	    passwordHash: hashAtt.hash,
35	    salt: hashAtt.salt,
36	    role: 'Attendant',
37	    siteId,
38	    failedAttempts: 0
39	  });
40	
41	  const actor = (await db.users.get(attId))!;
42	  const admin = (await db.users.get(adminId))!;
