3	async function loginAs(page: import('@playwright/test').Page, username: string, password: string) {
4	  await page.goto('/login');
5	  await expect(page.locator('#username')).toBeVisible({ timeout: 15_000 });
6	  await page.fill('#username', username);
7	  await page.fill('#password', password);
8	  await page.click('button[type="submit"]');
9	  await page.waitForURL(/\/(admin|kiosk)/, { timeout: 15_000 });
10	}
