12	/**
13	 * Navigate to a page and dismiss the unlock modal if it appears.
14	 * The modal appears after a full-page reload restores a saved session.
15	 * We wait briefly for any async restoreSession to complete before checking.
16	 */
17	async function gotoAndUnlock(
18	  page: import('@playwright/test').Page,
19	  url: string,
20	  password: string
21	) {
22	  await page.goto(url);
23	  // Give the async restoreSession useEffect time to run and potentially show the overlay.
24	  await page.waitForTimeout(1_000);
25	  const unlockBtn = page.locator('button:has-text("Unlock")');
26	  const unlockVisible = await unlockBtn.isVisible({ timeout: 5_000 }).catch(() => false);
27	  if (unlockVisible) {
28	    await page.fill('input[type="password"]', password);
29	    await page.click('button:has-text("Unlock")');
30	    // Wait for unlock modal to disappear
31	    await expect(unlockBtn).toHaveCount(0, { timeout: 10_000 });
32	  }
33	}
