32	function bytesToHex(bytes: Uint8Array): string {
33	  return [...bytes].map((b) => b.toString(16).padStart(2, '0')).join('');
34	}
35	
36	function hexToBytes(hex: string): Uint8Array {
37	  const out = new Uint8Array(hex.length / 2);
38	  for (let index = 0; index < out.length; index += 1) {
39	    out[index] = Number.parseInt(hex.slice(index * 2, index * 2 + 2), 16);
40	  }
41	  return out;
42	}
43	
44	function bytesToBase64(bytes: Uint8Array): string {
45	  let binary = '';
46	  for (const byte of bytes) binary += String.fromCharCode(byte);
47	  return btoa(binary);
48	}
49	
50	function base64ToBytes(base64: string): Uint8Array {
51	  const binary = atob(base64);
52	  const out = new Uint8Array(binary.length);
53	  for (let i = 0; i < binary.length; i += 1) out[i] = binary.charCodeAt(i);
54	  return out;
55	}
