94	    orders,
95	    reservationsCold,
96	    sessionsCold,
97	    ordersCold
98	  });
99	  const signature = await sha256Hex(payload + password);
100	  const salt = bytesToHex(crypto.getRandomValues(new Uint8Array(16)));
101	  const key = await cryptoService.deriveEncryptionKey(password, salt);
102	  const iv = crypto.getRandomValues(new Uint8Array(12));
103	  const cipher = await crypto.subtle.encrypt(
104	    { name: 'AES-GCM', iv },
105	    key,
106	    new TextEncoder().encode(payload)
107	  );
