109	  const pkg: ExportPackage = {
110	    version: 1,
111	    siteId,
112	    exportedAt: Date.now(),
113	    exportedBy: actor.username,
114	    dateRange,
115	    signature,
116	    salt,
117	    iv: bytesToHex(iv),
118	    ciphertext: bytesToBase64(new Uint8Array(cipher))
119	  };
