135	async function importPackage(file: File, password: string, actor: User): Promise<{ inserted: number; skipped: number }> {
136	  assertCanMutate(actor);
137	  // (package already carries siteId - no scope assertion on import)
138	  const text =
139	    'text' in file
140	      ? await (file as unknown as { text: () => Promise<string> }).text()
141	      : await new Promise<string>((resolve, reject) => {
142	          const reader = new FileReader();
143	          reader.onload = () => resolve(String(reader.result ?? ''));
144	          reader.onerror = () => reject(reader.error);
145	          reader.readAsText(file);
146	        });
147	
148	  const pkg = JSON.parse(text) as ExportPackage;
149	  if (pkg.version !== 1) {
150	    throw new Error('EXPORT_SIGNATURE_MISMATCH');
151	  }
152	
153	  assertSiteScope(actor, pkg.siteId);
154	
155	  try {
156	    const key = await cryptoService.deriveEncryptionKey(password, pkg.salt);
157	    const iv = hexToBytes(pkg.iv);
158	    const plain = await crypto.subtle.decrypt(
159	      { name: 'AES-GCM', iv: iv as unknown as BufferSource },
160	      key,
161	      base64ToBytes(pkg.ciphertext) as unknown as BufferSource
162	    );
163	    const payloadText = new TextDecoder().decode(plain);
164	    const signature = await sha256Hex(payloadText + password);
165	    if (signature !== pkg.signature) {
166	      throw new Error('EXPORT_SIGNATURE_MISMATCH');
167	    }
168	
169	    const payload = JSON.parse(payloadText) as {
170	      reservations: Array<{ id?: number }>;
171	      sessions: Array<{ id?: number }>;
172	      orders: Array<{ id?: number }>;
173	      reservationsCold: Array<{ id?: number }>;
174	      sessionsCold: Array<{ id?: number }>;
175	      ordersCold: Array<{ id?: number }>;
176	    };
177	
178	    let inserted = 0;
179	    let skipped = 0;
180	    for (const row of payload.reservations) {
181	      if (row.id && (await db.reservations.get(row.id))) {
182	        skipped += 1;
183	      } else {
184	        await db.reservations.add(row as never);
185	        inserted += 1;
186	      }
187	    }
188	    for (const row of payload.sessions) {
189	      if (row.id && (await db.sessions_charging.get(row.id))) {
190	        skipped += 1;
191	      } else {
192	        await db.sessions_charging.add(row as never);
193	        inserted += 1;
194	      }
195	    }
196	    for (const row of payload.orders) {
197	      if (row.id && (await db.orders.get(row.id))) {
198	        skipped += 1;
199	      } else {
200	        await db.orders.add(row as never);
201	        inserted += 1;
202	      }
203	    }
204	    for (const row of payload.reservationsCold) {
205	      if (row.id && (await db.reservations_cold.get(row.id))) {
206	        skipped += 1;
207	      } else {
208	        await db.reservations_cold.add(row as never);
209	        inserted += 1;
210	      }
211	    }
212	    for (const row of payload.sessionsCold) {
213	      if (row.id && (await db.sessions_cold.get(row.id))) {
214	        skipped += 1;
215	      } else {
216	        await db.sessions_cold.add(row as never);
217	        inserted += 1;
218	      }
219	    }
220	    for (const row of payload.ordersCold) {
221	      if (row.id && (await db.orders_cold.get(row.id))) {
222	        skipped += 1;
223	      } else {
224	        await db.orders_cold.add(row as never);
225	        inserted += 1;
226	      }
227	    }
228	
229	    await auditService.log(actor, 'IMPORT_PACKAGE_APPLIED', 'Site', pkg.siteId, { inserted, skipped });
230	    return { inserted, skipped };
231	  } catch {
232	    throw new Error('EXPORT_SIGNATURE_MISMATCH');
