12	async function runTiering(siteId: number, actor: User): Promise<TieringResult> {
13	  assertCanMutate(actor);
14	  assertSiteScope(actor, siteId);
15	  const cutoff = Date.now() - 90 * 24 * 60 * 60 * 1000;
16	  let reservationsArchived = 0;
17	  let sessionsArchived = 0;
18	  let ordersArchived = 0;
19	
20	  const reservations = await db.reservations
21	    .where('siteId')
22	    .equals(siteId)
23	    .filter((r) => r.scheduledStart < cutoff)
24	    .toArray();
25	  await db.transaction('rw', db.reservations, db.reservations_cold, async () => {
26	    for (const row of reservations) {
27	      const { id, ...rest } = row;
28	      await db.reservations_cold.add({
29	        ...rest,
30	        originalId: id as number,
31	        archivedAt: Date.now()
32	      });
33	      await db.reservations.delete(id as number);
34	      reservationsArchived += 1;
35	    }
36	  });
37	
38	  const sessions = await db.sessions_charging
39	    .where('siteId')
40	    .equals(siteId)
41	    .filter((s) => s.startedAt < cutoff)
42	    .toArray();
43	  await db.transaction('rw', db.sessions_charging, db.sessions_cold, async () => {
44	    for (const row of sessions) {
45	      const { id, ...rest } = row;
46	      await db.sessions_cold.add({
47	        ...rest,
48	        originalId: id as number,
49	        archivedAt: Date.now()
50	      });
51	      await db.sessions_charging.delete(id as number);
52	      sessionsArchived += 1;
53	    }
54	  });
55	
56	  const orders = await db.orders
57	    .where('siteId')
58	    .equals(siteId)
59	    .filter((o) => (o as { createdAt?: number }).createdAt ? (o as { createdAt: number }).createdAt < cutoff : false)
60	    .toArray();
61	  await db.transaction('rw', db.orders, db.orders_cold, async () => {
62	    for (const row of orders) {
63	      const { id, ...rest } = row;
64	      await db.orders_cold.add({
65	        ...rest,
66	        originalId: id as number,
67	        archivedAt: Date.now()
68	      });
69	      await db.orders.delete(id as number);
70	      ordersArchived += 1;
71	    }
72	  });
73	
74	  localStorage.setItem(
75	    `cb_tiering_last_${siteId}`,
76	    JSON.stringify({
77	      ranAt: Date.now(),
78	      reservationsArchived,
79	      sessionsArchived,
80	      ordersArchived
81	    })
82	  );
83	  await auditService.log(actor, 'TIERING_RUN', 'Site', siteId, {
84	    reservationsArchived,
85	    sessionsArchived,
86	    ordersArchived
87	  });
88	
89	  return { reservationsArchived, sessionsArchived, ordersArchived };
90	}
