1	interface WindowState {
2	  count: number;
3	  windowStart: number;
4	}
5	
6	export class RateLimitError extends Error {
7	  code = 'RATE_LIMIT_EXCEEDED' as const;
8	  action: string;
9	  cap: number;
10	  windowMs: number;
11	  retryAfterMs: number;
12	
13	  constructor(action: string, cap: number, windowMs: number, retryAfterMs: number) {
14	    super('RATE_LIMIT_EXCEEDED');
15	    this.action = action;
16	    this.cap = cap;
17	    this.windowMs = windowMs;
18	    this.retryAfterMs = retryAfterMs;
19	  }
20	}
21	
22	function key(userId: number, action: string) {
23	  return `cb_ratelimit_${userId}_${action}`;
24	}
25	
26	function readState(userId: number, action: string): WindowState {
27	  const raw = localStorage.getItem(key(userId, action));
28	  if (!raw) {
29	    return { count: 0, windowStart: Date.now() };
30	  }
31	  try {
32	    return JSON.parse(raw) as WindowState;
33	  } catch {
34	    return { count: 0, windowStart: Date.now() };
35	  }
36	}
37	
38	function writeState(userId: number, action: string, state: WindowState): void {
39	  localStorage.setItem(key(userId, action), JSON.stringify(state));
40	}
41	
42	class RateLimiter {
43	  check(userId: number, action: string, cap: number, windowMs: number, incomingCount = 1): void {
44	    const now = Date.now();
45	    const current = readState(userId, action);
46	    if (now - current.windowStart > windowMs) {
47	      writeState(userId, action, { count: 0, windowStart: now });
48	      return;
49	    }
50	    if (current.count + incomingCount > cap) {
51	      throw new RateLimitError(action, cap, windowMs, windowMs - (now - current.windowStart));
52	    }
53	  }
54	
55	  record(userId: number, action: string, count: number): void {
56	    const now = Date.now();
57	    const current = readState(userId, action);
58	    if (now - current.windowStart > 60_000) {
59	      writeState(userId, action, { count, windowStart: now });
60	      return;
61	    }
62	    writeState(userId, action, {
63	      count: current.count + count,
64	      windowStart: current.windowStart
65	    });
66	  }
67	}
68	
69	export const rateLimiter = new RateLimiter();
