68	function defaultPrefs(userId: number): NotificationPrefs {
69	  const enabled = Object.keys(TEMPLATES).reduce((acc, key) => {
70	    acc[key as NotificationTemplate] = true;
71	    return acc;
72	  }, {} as Record<NotificationTemplate, boolean>);
