81	function getPrefs(userId: number): NotificationPrefs {
82	  const raw = localStorage.getItem(prefsKey(userId));
83	  if (!raw) {
84	    return defaultPrefs(userId);
85	  }
86	
87	  try {
88	    const parsed = JSON.parse(raw) as NotificationPrefs;
89	    return {
90	      ...defaultPrefs(userId),
91	      ...parsed,
92	      enabled: {
93	        ...defaultPrefs(userId).enabled,
94	        ...parsed.enabled
95	      }
96	    };
97	  } catch {
98	    return defaultPrefs(userId);
99	  }
