116	async function deliver(notificationId: number): Promise<void> {
117	  const notification = await db.notifications.get(notificationId);
118	  if (!notification || notification.status === 'Archived') {
119	    return;
120	  }
121	
122	  try {
123	    const template = TEMPLATES[notification.templateKey];
124	    const renderedSubject = renderTemplate(template.subject, notification.templateData);
125	    const renderedBody = renderTemplate(template.body, notification.templateData);
126	    await db.notifications.update(notificationId, {
127	      status: 'Delivered',
128	      renderedSubject,
129	      renderedBody,
130	      lastAttemptAt: Date.now(),
131	      failureReason: undefined
132	    });
133	
134	    const prefs = getPrefs(notification.recipientId);
135	    if (prefs.showDesktopBanner && bannerListener) {
136	      bannerListener(renderedSubject, notification.recipientId);
137	    }
138	  } catch (error) {
139	    const retries = notification.retries + 1;
140	    const message = error instanceof Error ? error.message : 'Delivery error';
141	    await db.notifications.update(notificationId, {
142	      retries,
143	      failureReason: message,
144	      lastAttemptAt: Date.now(),
145	      status: retries >= 3 ? 'Failed' : 'Pending'
146	    });
147	
148	    if (retries < 3) {
149	      window.setTimeout(() => {
150	        void deliver(notificationId);
151	      }, 5_000);
152	    }
153	  }
154	}
