239	async function runDueAndOverdueSchedulers(actor: User): Promise<void> {
240	  assertCanMutate(actor);
241	  const now = Date.now();
242	  const reservations = await db.reservations
243	    .where('status')
244	    .equals('Scheduled')
245	    .filter((r) => (actor.role === 'SystemAdministrator' ? true : r.siteId === actor.siteId))
246	    .toArray();
247	
248	  for (const reservation of reservations) {
249	    const dueMin = reservation.scheduledStart - now;
250	    if (dueMin >= 14 * 60_000 && dueMin <= 16 * 60_000 && !sentDueReminder.has(reservation.id as number)) {
251	      sentDueReminder.add(reservation.id as number);
