254	        startTime: new Date(reservation.scheduledStart).toLocaleTimeString()
255	      });
256	    }
257	
258	    if (
259	      reservation.scheduledStart + 5 * 60_000 <= now &&
260	      !sentOverdueAlert.has(reservation.id as number)
261	    ) {
262	      sentOverdueAlert.add(reservation.id as number);
263	      await sendTemplateToSiteStaff(reservation.siteId, 'OVERDUE_ALERT', actor, {
