7	async function tick(actor: User): Promise<void> {
8	  assertCanMutate(actor);
9	  const now = Date.now();
10	  const sessions = await db.sessions_charging
11	    .where('status')
12	    .equals('Active')
13	    .filter((session) =>
14	      actor.role === 'SystemAdministrator' ? true : session.siteId === actor.siteId
15	    )
16	    .toArray();
17	
18	  for (const session of sessions) {
19	    await db.sessions_charging.update(session.id as number, {
20	      heartbeatAt: now,
21	      version: session.version + 1
22	    });
23	  }
24	}
25	
26	async function checkAnomalies(actor: User): Promise<void> {
27	  assertCanMutate(actor);
28	  const siteId = actor.siteId;
29	  const now = Date.now();
30	
31	  const targetSites =
32	    actor.role === 'SystemAdministrator'
33	      ? await db.sites.toArray().then((sites) => sites.map((site) => site.id as number))
34	      : [siteId as number];
35	
36	  for (const currentSiteId of targetSites) {
37	    const config = siteConfigService.getSiteConfig(currentSiteId);
38	    const heartbeatCutoff = now - config.anomalyHeartbeatTimeoutMin * 60_000;
39	    const tempLeaveCutoff = now - config.tempLeaveMaxMinutes * 60_000;
40	
41	    const noHeartbeat = await db.sessions_charging
42	      .where('status')
43	      .equals('Active')
44	      .filter((session) => session.siteId === currentSiteId && session.heartbeatAt < heartbeatCutoff)
45	      .toArray();
46	
47	    for (const session of noHeartbeat) {
48	      await reservationService.flagAnomaly(session.id as number, `No heartbeat for ${config.anomalyHeartbeatTimeoutMin}+ minutes`, actor);
49	    }
50	
51	    const tempLeaveExceeded = await db.sessions_charging
52	      .where('status')
53	      .equals('TempLeave')
54	      .filter(
55	        (session) =>
56	          session.siteId === currentSiteId &&
57	          typeof session.tempLeaveStartedAt === 'number' &&
58	          session.tempLeaveStartedAt < tempLeaveCutoff
59	      )
60	      .toArray();
61	
62	    for (const session of tempLeaveExceeded) {
63	      await reservationService.flagAnomaly(session.id as number, 'Temp leave duration exceeded', actor);
64	    }
65	  }
66	}
67	
68	export const heartbeatService = {
69	  tick,
70	  checkAnomalies
71	};
