1	import { db } from '../db/db';
2	import type { QualityReport, User } from '../types';
3	import { auditService } from './auditService';
4	import { notificationService } from './notificationService';
5	import { assertManagerOrAdmin, assertSiteScope } from './rbacService';
6	
7	interface TableStat {
8	  table: string;
9	  totalRows: number;
10	  missingFieldRows: number;
11	  completenessPct: number;
12	  duplicateRows: number;
13	}
14	
15	interface ReportDetail {
16	  generatedAt: number;
17	  stats: TableStat[];
18	}
19	
20	function completeness(total: number, missing: number): number {
21	  if (total === 0) {
22	    return 100;
23	  }
24	  return Number((((total - missing) / total) * 100).toFixed(2));
25	}
26	
27	async function runReport(siteId: number, actor: User): Promise<QualityReport> {
28	  assertManagerOrAdmin(actor);
29	  assertSiteScope(actor, siteId);
30	  const reservations = await db.reservations.where('siteId').equals(siteId).toArray();
31	  const orders = await db.orders.where('siteId').equals(siteId).toArray();
32	  const sessions = await db.sessions_charging.where('siteId').equals(siteId).toArray();
33	
34	  const reservationMissing = reservations.filter((r) => !r.customerName || !r.customerPlate).length;
35	  const orderMissing = orders.filter((o) => !o.orderNumber).length;
36	  const sessionMissing = sessions.filter((s) => !s.reservationId || !s.startedAt).length;
37	
38	  const reservationKeyCount = new Map<string, number>();
39	  reservations.forEach((r) => {
40	    const key = `${r.bayId}_${r.scheduledStart}`;
41	    reservationKeyCount.set(key, (reservationKeyCount.get(key) ?? 0) + 1);
42	  });
43	  const reservationDuplicates = [...reservationKeyCount.values()].filter((count) => count > 1).length;
44	
45	  const orderKeyCount = new Map<string, number>();
46	  orders.forEach((o) => {
47	    orderKeyCount.set(o.orderNumber, (orderKeyCount.get(o.orderNumber) ?? 0) + 1);
48	  });
49	  const orderDuplicates = [...orderKeyCount.values()].filter((count) => count > 1).length;
50	
51	  const stats: TableStat[] = [
52	    {
53	      table: 'reservations',
54	      totalRows: reservations.length,
55	      missingFieldRows: reservationMissing,
56	      completenessPct: completeness(reservations.length, reservationMissing),
57	      duplicateRows: reservationDuplicates
58	    },
59	    {
60	      table: 'orders',
61	      totalRows: orders.length,
62	      missingFieldRows: orderMissing,
63	      completenessPct: completeness(orders.length, orderMissing),
64	      duplicateRows: orderDuplicates
65	    },
66	    {
67	      table: 'sessions_charging',
68	      totalRows: sessions.length,
69	      missingFieldRows: sessionMissing,
70	      completenessPct: completeness(sessions.length, sessionMissing),
71	      duplicateRows: 0
72	    }
73	  ];
74	
75	  const detail: ReportDetail = {
76	    generatedAt: Date.now(),
77	    stats
78	  };
79	
80	  const reportId = await db.qualityReports.add({
81	    siteId,
82	    generatedAt: detail.generatedAt,
83	    type: 'Weekly',
84	    detail: JSON.stringify(detail)
85	  });
86	  await auditService.log(actor, 'QUALITY_REPORT_GENERATED', 'QualityReport', reportId);
87	
88	  const recipients = await db.users.where('siteId').equals(siteId).toArray();
89	  for (const user of recipients) {
90	    if (user.role === 'SiteManager') {
91	      await notificationService.send(user.id as number, 'QUALITY_REPORT_READY', {
92	        siteName: String(siteId),
93	        issues: String(stats.reduce((acc, row) => acc + row.missingFieldRows + row.duplicateRows, 0))
94	      });
95	    }
96	  }
97	  const sysAdmins = await db.users.where('role').equals('SystemAdministrator').toArray();
98	  for (const admin of sysAdmins) {
99	    await notificationService.send(admin.id as number, 'QUALITY_REPORT_READY', {
100	      siteName: String(siteId),
101	      issues: String(stats.reduce((acc, row) => acc + row.missingFieldRows + row.duplicateRows, 0))
102	    });
103	  }
104	
105	  return (await db.qualityReports.get(reportId)) as QualityReport;
106	}
107	
108	function exportReportCsv(report: QualityReport): void {
109	  const detail = JSON.parse(report.detail) as ReportDetail;
110	  const lines = [
111	    'table,completeness_pct,total_rows,missing_field_rows,duplicate_rows',
112	    ...detail.stats.map(
113	      (row) =>
114	        `${row.table},${row.completenessPct},${row.totalRows},${row.missingFieldRows},${row.duplicateRows}`
115	    )
116	  ];
117	
118	  const blob = new Blob([lines.join('\n')], { type: 'text/csv' });
119	  const url = URL.createObjectURL(blob);
120	  const a = document.createElement('a');
121	  a.href = url;
122	  a.download = `quality_report_${report.siteId}_${report.generatedAt}.csv`;
123	  a.click();
124	  URL.revokeObjectURL(url);
125	}
126	
127	async function runWeeklyIfDue(siteId: number, actor: User): Promise<boolean> {
128	  const key = `cb_quality_lastRun_${siteId}`;
129	  const now = Date.now();
130	  const lastRun = Number(localStorage.getItem(key) ?? 0);
131	  if (now - lastRun <= 7 * 24 * 60 * 60 * 1000) {
132	    return false;
133	  }
134	
135	  await runReport(siteId, actor);
136	  localStorage.setItem(key, String(now));
137	  return true;
138	}
139	
140	export const qualityService = {
141	  runReport,
142	  exportReportCsv,
143	  runWeeklyIfDue
144	};
