64	/**
65	 * RFC 4180-oriented parser for the import workflows.
66	 * Handles quoted fields, embedded commas, doubled-quote escapes (""),
67	 * and embedded newlines inside quoted cells.
68	 */
69	function parseCsv(csv: string): { headers: string[]; rows: Record<string, string>[] } {
70	  const records: string[][] = [];
71	  let row: string[] = [];
72	  let cell = '';
73	  let inQuotes = false;
74	
75	  for (let index = 0; index < csv.length; index += 1) {
76	    const ch = csv[index];
77	
78	    if (inQuotes) {
79	      if (ch === '"') {
80	        if (csv[index + 1] === '"') {
81	          cell += '"';
82	          index += 1;
83	        } else {
84	          inQuotes = false;
85	        }
86	      } else {
87	        cell += ch;
88	      }
89	      continue;
90	    }
91	
92	    if (ch === '"') {
93	      inQuotes = true;
94	      continue;
95	    }
96	
97	    if (ch === ',') {
98	      row.push(cell.trim());
99	      cell = '';
100	      continue;
101	    }
102	
103	    if (ch === '\n') {
104	      row.push(cell.trim());
105	      if (row.some((entry) => entry.length > 0)) {
106	        records.push(row);
107	      }
108	      row = [];
109	      cell = '';
110	      continue;
111	    }
112	
113	    if (ch !== '\r') {
114	      cell += ch;
115	    }
116	  }
117	
118	  row.push(cell.trim());
119	  if (row.some((entry) => entry.length > 0)) {
120	    records.push(row);
121	  }
122	
123	  if (records.length === 0) {
124	    return { headers: [], rows: [] };
125	  }
126	
127	  const [headers, ...dataRows] = records;
128	  const rows = dataRows.map((cells) => {
129	    const parsedRow: Record<string, string> = {};
130	    headers.forEach((header, index) => {
131	      parsedRow[header] = (cells[index] ?? '').trim();
132	    });
133	    return parsedRow;
134	  });
135	
136	  return { headers, rows };
137	}
138	
139	export function parseDate(value: string): number | null {
140	  // Full datetime format: MM/DD/YYYY HH:mm
141	  const fullMatch = value.match(/^(\d{2})\/(\d{2})\/(\d{4})\s(\d{2}):(\d{2})$/);
142	  if (fullMatch) {
143	    const [, mm, dd, yyyy, hh, min] = fullMatch;
144	    const month = Number(mm);
145	    const day = Number(dd);
146	    if (month < 1 || month > 12 || day < 1 || day > 31) return null;
147	    const date = new Date(Number(yyyy), month - 1, day, Number(hh), Number(min));
148	    return Number.isNaN(date.getTime()) ? null : date.getTime();
149	  }
150	  // Date-only format: MM/DD/YYYY — defaults to 00:00 local time
151	  const dateMatch = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
152	  if (dateMatch) {
153	    const [, mm, dd, yyyy] = dateMatch;
154	    const month = Number(mm);
155	    const day = Number(dd);
156	    if (month < 1 || month > 12 || day < 1 || day > 31) return null;
157	    const date = new Date(Number(yyyy), month - 1, day, 0, 0);
158	    return Number.isNaN(date.getTime()) ? null : date.getTime();
159	  }
160	  return null;
161	}
