163	async function sha256(text: string): Promise<string> {
164	  const buffer = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(text));
165	  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, '0')).join('');
166	}
