168	async function parseFile(file: File): Promise<{ headers: string[]; rows: Record<string, string>[]; raw: string }> {
169	  const readAsText =
170	    'text' in file
171	      ? async () => (await (file as unknown as { text: () => Promise<string> }).text())
172	      : async () =>
173	          await new Promise<string>((resolve, reject) => {
174	            const reader = new FileReader();
175	            reader.onload = () => resolve(String(reader.result ?? ''));
176	            reader.onerror = () => reject(reader.error);
177	            reader.readAsText(file);
178	          });
179	
180	  const readAsArrayBuffer =
181	    'arrayBuffer' in file
182	      ? async () =>
183	          await (file as unknown as { arrayBuffer: () => Promise<ArrayBuffer> }).arrayBuffer()
184	      : async () =>
185	          await new Promise<ArrayBuffer>((resolve, reject) => {
186	            const reader = new FileReader();
187	            reader.onload = () => resolve(reader.result as ArrayBuffer);
188	            reader.onerror = () => reject(reader.error);
189	            reader.readAsArrayBuffer(file);
190	          });
191	
192	  if (file.name.toLowerCase().endsWith('.xlsx')) {
193	    const bytes = await readAsArrayBuffer();
194	    const workbook = XLSX.read(bytes, { type: 'array' });
195	    const sheet = workbook.Sheets[workbook.SheetNames[0]];
196	    const matrix = XLSX.utils.sheet_to_json<(string | number)[]>(sheet, { header: 1 });
197	    const [headersRow = [], ...body] = matrix;
198	    const headers = headersRow.map((cell) => String(cell).trim());
199	    const rows = body.map((cells) => {
200	      const row: Record<string, string> = {};
201	      headers.forEach((header, index) => {
202	        row[header] = String(cells[index] ?? '').trim();
203	      });
204	      return row;
205	    });
206	    return { headers, rows, raw: JSON.stringify(matrix) };
207	  }
208	
209	  const text = await readAsText();
210	  const parsed = parseCsv(text);
211	  return { ...parsed, raw: text };
212	}
