214	function applyFieldMap(row: Record<string, string>, fieldMap: FieldMap): Record<string, string> {
215	  const mapped: Record<string, string> = {};
216	  Object.entries(fieldMap).forEach(([source, target]) => {
217	    if (target) {
218	      mapped[target] = row[source] ?? '';
219	    }
220	  });
221	  return mapped;
222	}
