297	function autoMapFields(headers: string[], type: ImportType): FieldMap {
298	  const required = REQUIRED_FIELDS[type];
299	  const lowerMap = new Map(required.map((field) => [field.toLowerCase(), field]));
300	  const map: FieldMap = {};
301	  headers.forEach((header) => {
302	    const target = lowerMap.get(header.toLowerCase());
303	    map[header] = target ?? '';
304	  });
305	  return map;
306	}
307	
308	function generateCsv(rows: string[][]): string {
309	  return rows.map((line) => line.join(',')).join('\n');
310	}
