312	function downloadTemplate(type: ImportType): void {
313	  const def = TEMPLATE_ROWS[type];
314	  const csv = generateCsv([def.headers, def.sample]);
315	  const blob = new Blob([csv], { type: 'text/csv' });
316	  const url = URL.createObjectURL(blob);
317	  const a = document.createElement('a');
318	  a.href = url;
319	  a.download = `${type}_template.csv`;
320	  a.click();
321	  URL.revokeObjectURL(url);
322	}
