342	async function startImport(
343	  file: File,
344	  type: ImportType,
345	  fieldMap: FieldMap,
346	  actor: User,
347	  encryptionKey?: CryptoKey
348	): Promise<ImportBatch> {
349	  assertManagerOrAdmin(actor);
350	
351	  if (type !== 'sessions' && !encryptionKey) {
352	    throw new Error('IMPORT_ENCRYPTION_KEY_REQUIRED');
353	  }
354	
355	  const parsed = await parseFile(file);
356	  const dedupeHash = await sha256(parsed.raw);
357	
358	  const existingBatch = await db.importBatches
359	    .where('siteId')
360	    .equals(actor.siteId as number)
361	    .filter((b) => b.dedupeHash === dedupeHash)
362	    .first();
363	  if (existingBatch) {
364	    throw new Error('IMPORT_DUPLICATE_FILE');
365	  }
366	
367	  const batchId = await db.importBatches.add({
368	    siteId: actor.siteId as number,
369	    type,
370	    status: 'Validating',
371	    createdAt: Date.now(),
372	    dedupeHash
373	  });
374	
375	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
376	  const validation = await validateRows(mappedRows, type, actor);
377	  const validationRows = validation.importRows.map((row) => ({ ...row, batchId }));
378	  await db.importRows.bulkAdd(validationRows);
379	
380	  if (validation.invalidCount > 0) {
381	    await db.importBatches.update(batchId, {
382	      status: 'Failed',
383	      totalRows: mappedRows.length,
384	      validRows: validation.validCount,
385	      invalidRows: validation.invalidCount,
386	      duplicateRows: 0,
387	      errorSummary: `${validation.invalidCount} invalid rows`
388	    });
389	    await notificationService.send(actor.id as number, 'IMPORT_FAILED', {
390	      batchId: String(batchId),
391	      reason: `${validation.invalidCount} validation errors`
392	    });
393	    return (await db.importBatches.get(batchId)) as ImportBatch;
394	  }
395	
396	  // Pre-encrypt sensitive fields outside the Dexie transaction
397	  // (WebCrypto operations break IndexedDB transaction scope)
398	  const encryptedRows: Array<{ encName?: string; encPlate?: string; encNotes?: string }> = [];
399	  if (type === 'reservations' || type === 'orders') {
400	    for (const row of mappedRows) {
401	      if (type === 'reservations') {
402	        encryptedRows.push({
403	          encName: await cryptoService.encryptField(row.customerName, encryptionKey!),
404	          encPlate: await cryptoService.encryptField(row.customerPlate, encryptionKey!)
405	        });
406	      } else {
407	        encryptedRows.push({
408	          encNotes: await cryptoService.encryptField(row.invoiceNotes, encryptionKey!)
409	        });
410	      }
411	    }
412	  }
413	
414	  let duplicateRows = 0;
415	  await db.transaction(
416	    'rw',
417	    db.reservations,
418	    db.orders,
419	    db.sessions_charging,
420	    db.bays,
421	    db.importRows,
422	    async () => {
423	      for (let index = 0; index < mappedRows.length; index += 1) {
424	        const row = mappedRows[index];
425	        let isDuplicate = false;
426	
427	        if (type === 'reservations') {
428	          const start = parseDate(row.scheduledStart) as number;
429	          const bay = await db.bays
430	            .where('siteId')
431	            .equals(actor.siteId as number)
432	            .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
433	            .first();
434	
435	          const dup = await db.reservations
436	            .where('siteId')
437	            .equals(actor.siteId as number)
438	            .filter((r) => r.bayId === bay?.id && r.scheduledStart === start)
439	            .first();
440	          if (dup) {
441	            isDuplicate = true;
442	          } else {
443	            const encName = encryptedRows[index]!.encName!;
444	            const encPlate = encryptedRows[index]!.encPlate!;
445	            await db.reservations.add({
446	              operationId: crypto.randomUUID(),
447	              bayId: bay?.id as number,
448	              siteId: actor.siteId as number,
449	              userId: actor.id as number,
450	              customerName: encName,
451	              customerPlate: encPlate,
452	              scheduledStart: start,
453	              scheduledEnd: parseDate(row.scheduledEnd) as number,
454	              status: 'Scheduled',
455	              noShowDeadline: start + siteConfigService.getSiteConfig(actor.siteId as number).noShowGraceMinutes * 60_000,
456	              version: 1,
457	              importBatchId: batchId,
458	              importRowId: index + 1
459	            });
460	          }
461	        }
462	
463	        if (type === 'orders') {
464	          const dup = await db.orders
465	            .where('siteId')
466	            .equals(actor.siteId as number)
467	            .filter((o) => o.orderNumber === row.orderNumber)
468	            .first();
469	          if (dup) {
470	            isDuplicate = true;
471	          } else {
472	            const duration = Number(row.durationMinutes);
473	            const rate = Number(row.ratePerMinute);
474	            const adjustment = Number(row.adjustmentAmount);
475	            const subtotal = Number((duration * rate).toFixed(2));
476	            const encNotes = encryptedRows[index]!.encNotes!;
477	            await db.orders.add({
478	              operationId: crypto.randomUUID(),
479	              sessionId: Number(row.sessionId),
480	              siteId: actor.siteId as number,
481	              orderNumber: row.orderNumber,
482	              status: 'Draft',
483	              billingType: 'Standard',
484	              durationMinutes: duration,
485	              ratePerMinute: rate,
486	              subtotal,
487	              adjustmentAmount: adjustment,
488	              adjustmentReason: row.adjustmentReason,
489	              totalAmount: Number((subtotal + adjustment).toFixed(2)),
490	              invoiceNotes: encNotes,
491	              reconciliationStatus: 'Unreconciled',
492	              version: 1,
493	              importBatchId: batchId,
494	              importRowId: index + 1
495	            });
496	          }
497	        }
498	
499	        if (type === 'sessions') {
500	          const startedAt = parseDate(row.startedAt);
501	          const dup = await db.sessions_charging
502	            .where('reservationId')
503	            .equals(Number(row.reservationId))
504	            .filter((s) => s.startedAt === startedAt)
505	            .first();
506	          if (dup) {
507	            isDuplicate = true;
508	          } else {
509	            const reservation = await db.reservations.get(Number(row.reservationId));
510	            if (reservation) {
511	              await db.sessions_charging.add({
512	                reservationId: reservation.id as number,
513	                bayId: reservation.bayId,
514	                siteId: reservation.siteId,
515	                startedAt: startedAt as number,
516	                status: 'Active',
517	                heartbeatAt: startedAt as number,
518	                tempLeaveCount: 0,
519	                version: 1,
520	                importBatchId: batchId,
521	                importRowId: index + 1
522	              });
523	            }
524	          }
