interface WindowState {
  count: number;
  windowStart: number;
}

export class RateLimitError extends Error {
  code = 'RATE_LIMIT_EXCEEDED' as const;
  action: string;
  cap: number;
  windowMs: number;
  retryAfterMs: number;

  constructor(action: string, cap: number, windowMs: number, retryAfterMs: number) {
    super('RATE_LIMIT_EXCEEDED');
    this.action = action;
    this.cap = cap;
    this.windowMs = windowMs;
    this.retryAfterMs = retryAfterMs;
  }
}

function compositeKey(userId: number, action: string) {
  return `cb_ratelimit_${userId}_${action}`;
}

function readStateSync(userId: number, action: string): WindowState {
  const raw = localStorage.getItem(compositeKey(userId, action));
  if (!raw) {
    return { count: 0, windowStart: Date.now() };
  }
  try {
    return JSON.parse(raw) as WindowState;
  } catch {
    return { count: 0, windowStart: Date.now() };
  }
}

function writeStateSync(userId: number, action: string, state: WindowState): void {
  localStorage.setItem(compositeKey(userId, action), JSON.stringify(state));
}

async function persistToIdb(userId: number, action: string, state: WindowState): Promise<void> {
  try {
    await db.rateLimits.put({ key: compositeKey(userId, action), ...state });
  } catch { /* IndexedDB write failure is non-fatal; localStorage is authoritative for sync reads */ }
}

async function loadFromIdb(userId: number, action: string): Promise<WindowState | null> {
  try {
    const record = await db.rateLimits.get(compositeKey(userId, action));
    return record ? { count: record.count, windowStart: record.windowStart } : null;
  } catch {
    return null;
  }
}

class RateLimiter {
  check(userId: number, action: string, cap: number, windowMs: number, incomingCount = 1): void {
    const now = Date.now();
    const current = readStateSync(userId, action);
    if (now - current.windowStart > windowMs) {
      const reset = { count: 0, windowStart: now };
      writeStateSync(userId, action, reset);
      void persistToIdb(userId, action, reset);
      return;
    }
    if (current.count + incomingCount > cap) {
      throw new RateLimitError(action, cap, windowMs, windowMs - (now - current.windowStart));
    }
  }

  record(userId: number, action: string, count: number): void {
    const now = Date.now();
    const current = readStateSync(userId, action);
    let next: WindowState;
    if (now - current.windowStart > 60_000) {
      next = { count, windowStart: now };
    } else {
      next = { count: current.count + count, windowStart: current.windowStart };
    }
    writeStateSync(userId, action, next);
    void persistToIdb(userId, action, next);
  }

  async syncFromIdb(userId: number, action: string): Promise<void> {
    const idbState = await loadFromIdb(userId, action);
    if (idbState) {
      writeStateSync(userId, action, idbState);
    }
  }
}

export const rateLimiter = new RateLimiter();
"}

