  record(userId: number, action: string, count: number): void {
    const now = Date.now();
    const current = readStateSync(userId, action);
    let next: WindowState;
    if (now - current.windowStart > 60_000) {
      next = { count, windowStart: now };
    } else {
      next = { count: current.count + count, windowStart: current.windowStart };
    }
    writeStateSync(userId, action, next);
    void persistToIdb(userId, action, next);
  }

  async syncFromIdb(userId: number, action: string): Promise<void> {
    const idbState = await loadFromIdb(userId, action);
    if (idbState) {
      writeStateSync(userId, action, idbState);
    }
  }
}

export const rateLimiter = new RateLimiter();
"}

