3	interface WindowState {
4	  count: number;
5	  windowStart: number;
6	}
7	
8	export class RateLimitError extends Error {
9	  code = 'RATE_LIMIT_EXCEEDED' as const;
10	  action: string;
11	  cap: number;
12	  windowMs: number;
13	  retryAfterMs: number;
14	
15	  constructor(action: string, cap: number, windowMs: number, retryAfterMs: number) {
16	    super('RATE_LIMIT_EXCEEDED');
17	    this.action = action;
18	    this.cap = cap;
19	    this.windowMs = windowMs;
20	    this.retryAfterMs = retryAfterMs;
21	  }
22	}
23	
24	function compositeKey(userId: number, action: string) {
25	  return `cb_ratelimit_${userId}_${action}`;
26	}
27	
28	function readStateSync(userId: number, action: string): WindowState {
29	  const raw = localStorage.getItem(compositeKey(userId, action));
30	  if (!raw) {
31	    return { count: 0, windowStart: Date.now() };
32	  }
33	  try {
34	    return JSON.parse(raw) as WindowState;
35	  } catch {
36	    return { count: 0, windowStart: Date.now() };
37	  }
38	}
39	
40	function writeStateSync(userId: number, action: string, state: WindowState): void {
41	  localStorage.setItem(compositeKey(userId, action), JSON.stringify(state));
42	}
43	
44	async function persistToIdb(userId: number, action: string, state: WindowState): Promise<void> {
45	  try {
46	    await db.rateLimits.put({ key: compositeKey(userId, action), ...state });
47	  } catch { /* IndexedDB write failure is non-fatal; localStorage is authoritative for sync reads */ }
48	}
49	
50	async function loadFromIdb(userId: number, action: string): Promise<WindowState | null> {
51	  try {
52	    const record = await db.rateLimits.get(compositeKey(userId, action));
53	    return record ? { count: record.count, windowStart: record.windowStart } : null;
54	  } catch {
55	    return null;
56	  }
57	}
58	
59	class RateLimiter {
60	  check(userId: number, action: string, cap: number, windowMs: number, incomingCount = 1): void {
61	    const now = Date.now();
62	    const current = readStateSync(userId, action);
63	    if (now - current.windowStart > windowMs) {
64	      const reset = { count: 0, windowStart: now };
65	      writeStateSync(userId, action, reset);
66	      void persistToIdb(userId, action, reset);
67	      return;
68	    }
69	    if (current.count + incomingCount > cap) {
70	      throw new RateLimitError(action, cap, windowMs, windowMs - (now - current.windowStart));
71	    }
72	  }
73	
74	  record(userId: number, action: string, count: number): void {
75	    const now = Date.now();
76	    const current = readStateSync(userId, action);
77	    let next: WindowState;
78	    if (now - current.windowStart > 60_000) {
79	      next = { count, windowStart: now };
80	    } else {
81	      next = { count: current.count + count, windowStart: current.windowStart };
82	    }
83	    writeStateSync(userId, action, next);
84	    void persistToIdb(userId, action, next);
85	  }
86	
87	  async syncFromIdb(userId: number, action: string): Promise<void> {
88	    const idbState = await loadFromIdb(userId, action);
89	    if (idbState) {
90	      writeStateSync(userId, action, idbState);
91	    }
92	  }
93	}
94	
95	export const rateLimiter = new RateLimiter();
