65	function Runtime() {
66	  const { currentUser } = useAuth();
67	  const [banner, setBanner] = useState<string | null>(null);
68	
69	  useEffect(() => {
70	    if (!currentUser) {
71	      return;
72	    }
73	
74	    const siteId = currentUser.siteId;
75	    const canMutate = currentUser.role !== 'Auditor';
76	    if (siteId && canMutate) {
77	      void qualityService.runWeeklyIfDue(siteId, currentUser);
78	      void tieringService.runTiering(siteId, currentUser);
79	    }
80	
81	    // Tick heartbeat for all Active sessions every 5 minutes so normal long-running
82	    // sessions are not incorrectly escalated to Anomaly while the operator is present.
83	    // The anomaly check (every 1 min) only fires when the last tick is genuinely stale
84	    // – i.e. when the app has been closed/backgrounded beyond the configured timeout.
85	    if (canMutate) void heartbeatService.tick(currentUser);
86	    const heartbeatTickTimer = window.setInterval(() => {
87	      if (canMutate) void heartbeatService.tick(currentUser);
88	    }, 5 * 60_000);
89	
90	    const anomalyTimer = window.setInterval(() => {
91	      if (canMutate) void heartbeatService.checkAnomalies(currentUser);
92	    }, 60_000);
93	
94	    const noShowTimer = window.setInterval(() => {
95	      if (canMutate) void reservationService.autoProcessNoShows(currentUser);
96	    }, 60_000);
97	
98	    const notifRetryTimer = window.setInterval(() => {
99	      if (canMutate) void notificationService.retryFailed();
100	    }, 30_000);
101	
102	    const notifRuleTimer = window.setInterval(() => {
103	      if (canMutate) void notificationService.runDueAndOverdueSchedulers(currentUser);
104	    }, 60_000);
105	
106	    const clearBanner = window.setInterval(() => setBanner(null), 5_000);
107	    const tieringTimer = window.setInterval(() => {
108	      if (siteId && canMutate) {
109	        void tieringService.runTiering(siteId, currentUser);
110	      }
111	    }, 24 * 60 * 60 * 1000);
112	    notificationService.setBannerListener((subject, userId) => {
113	      if (currentUser.id === userId) {
114	        setBanner(subject);
115	      }
116	    });
117	
118	    return () => {
119	      window.clearInterval(heartbeatTickTimer);
120	      window.clearInterval(anomalyTimer);
121	      window.clearInterval(noShowTimer);
122	      window.clearInterval(notifRetryTimer);
123	      window.clearInterval(notifRuleTimer);
124	      window.clearInterval(clearBanner);
125	      window.clearInterval(tieringTimer);
126	      notificationService.setBannerListener(null);
127	    };
128	  }, [currentUser]);
129	
130	  if (!banner) {
131	    return null;
132	  }
133	
134	  return <div className="notif-banner">{banner}</div>;
135	}
