212	  const session = await db.sessions_charging.get(sessionId);
213	  if (!session) {
214	    throw new Error('SESSION_NOT_FOUND');
215	  }
216	  assertSiteScope(actor, session.siteId);
217	
218	  await db.sessions_charging.update(sessionId, {
219	    status: 'Anomaly',
220	    anomalyReason: reason,
221	    version: session.version + 1
222	  });
223	  await db.bays.update(session.bayId, { status: 'Anomaly' });
224	  await notificationService.sendTemplateToSiteStaff(session.siteId, 'OCCUPANCY_ANOMALY', actor, {
225	    bayLabel: String(session.bayId),
226	    reason
227	  });
