231	async function startTempLeave(sessionId: number, actor: User): Promise<void> {
232	  assertCanMutate(actor);
233	  const session = await db.sessions_charging.get(sessionId);
234	  if (!session || session.status !== 'Active') {
235	    throw new Error('SESSION_INVALID_STATE');
236	  }
237	  assertSiteScope(actor, session.siteId);
238	
239	  const config = siteConfigService.getSiteConfig(session.siteId);
240	  if (session.tempLeaveCount >= config.tempLeaveMaxCount) {
241	    // Prompt requires: exceeding temp-leave count limit triggers Unverified Occupancy anomaly.
242	    await flagAnomaly(sessionId, 'Unverified Occupancy: temp leave count limit exceeded', actor);
243	    throw new TempLeaveLimitError();
244	  }
245	
246	  await db.sessions_charging.update(sessionId, {
247	    status: 'TempLeave',
248	    tempLeaveStartedAt: Date.now(),
249	    version: session.version + 1
250	  });
251	  await auditService.log(actor, 'TEMP_LEAVE_STARTED', 'ChargingSession', sessionId);
252	}
253	
254	async function endTempLeave(sessionId: number, actor: User): Promise<void> {
255	  assertCanMutate(actor);
256	  const session = await db.sessions_charging.get(sessionId);
257	  if (!session || session.status !== 'TempLeave') {
258	    throw new Error('SESSION_INVALID_STATE');
259	  }
260	  assertSiteScope(actor, session.siteId);
261	
262	  const now = Date.now();
263	  const config = siteConfigService.getSiteConfig(session.siteId);
264	  const duration = now - (session.tempLeaveStartedAt ?? now);
265	
266	  if (duration > config.tempLeaveMaxMinutes * 60_000) {
267	    await flagAnomaly(sessionId, 'Temp leave duration exceeded', actor);
268	    return;
269	  }
270	
271	  await db.sessions_charging.update(sessionId, {
272	    status: 'Active',
273	    tempLeaveStartedAt: undefined,
274	    tempLeaveCount: session.tempLeaveCount + 1,
275	    heartbeatAt: now,
276	    version: session.version + 1
277	  });
278	  await auditService.log(actor, 'TEMP_LEAVE_ENDED', 'ChargingSession', sessionId);
279	}
