281	async function getReservationDetail(
282	  reservationId: number,
283	  actor: User,
284	  encryptionKey: CryptoKey
285	): Promise<Reservation | null> {
286	  const reservation = await db.reservations.get(reservationId);
287	  if (!reservation) {
288	    return null;
289	  }
290	  assertSiteScope(actor, reservation.siteId);
291	
292	  return {
293	    ...reservation,
294	    customerName: await cryptoService.decryptField(reservation.customerName, encryptionKey),
295	    customerPlate: await cryptoService.decryptField(reservation.customerPlate, encryptionKey)
