299	async function bulkCancelReservations(reservationIds: number[], actor: User): Promise<void> {
300	  assertCanMutate(actor);
301	  const userId = actor.id as number;
302	  rateLimiter.check(userId, 'bulk_reservation_cancel', 100, 60_000, reservationIds.length);
303	  rateLimiter.record(userId, 'bulk_reservation_cancel', reservationIds.length);
304	
305	  for (const reservationId of reservationIds) {
306	    const reservation = await db.reservations.get(reservationId);
307	    if (!reservation) {
308	      continue;
309	    }
310	    assertSiteScope(actor, reservation.siteId);
311	    await db.reservations.update(reservationId, { status: 'Cancelled', version: reservation.version + 1 });
312	    await db.bays.update(reservation.bayId, { status: 'Available' });
313	    await auditService.log(actor, 'RESERVATION_CANCELLED', 'Reservation', reservationId);
314	  }
315	}
