87	async function submitOrder(orderId: number, actor: User): Promise<void> {
88	  assertCanMutate(actor);
89	  const order = await db.orders.get(orderId);
90	  if (!order) {
91	    throw new Error('ORDER_NOT_FOUND');
92	  }
93	  assertSiteScope(actor, order.siteId);
94	
95	  if (order.billingType === 'Compensation' && actor.role === 'Attendant') {
