1	import { db } from '../db/db';
2	import type { User } from '../types';
3	import { auditService } from './auditService';
4	import { notificationService } from './notificationService';
5	import { orderService } from './orderService';
6	import { assertCanMutate, assertSiteScope } from './rbacService';
7	
8	function assertManagerOrAdmin(actor: User) {
9	  if (actor.role !== 'SystemAdministrator' && actor.role !== 'SiteManager') {
10	    throw new Error('RBAC_SCOPE_VIOLATION');
11	  }
12	}
13	
14	async function completeSession(sessionId: number, actor: User): Promise<void> {
15	  assertCanMutate(actor);
16	  const session = await db.sessions_charging.get(sessionId);
17	  if (!session || session.status !== 'Active') {
18	    throw new Error('SESSION_INVALID_STATE');
19	  }
20	  assertSiteScope(actor, session.siteId);
21	
22	  const now = Date.now();
23	  await db.sessions_charging.update(sessionId, {
24	    status: 'Completed',
25	    endedAt: now,
26	    version: session.version + 1
27	  });
28	  await db.bays.update(session.bayId, { status: 'Available' });
29	  await db.reservations.update(session.reservationId, { status: 'Completed' });
30	  await orderService.generateOrder(sessionId, actor);
31	  await notificationService.sendTemplateToSiteStaff(session.siteId, 'HOLD_AVAILABLE', actor, {
32	    bayLabel: String(session.bayId)
33	  });
34	  await auditService.log(actor, 'SESSION_COMPLETED', 'ChargingSession', sessionId);
35	}
36	
37	async function resolveAnomaly(
38	  sessionId: number,
39	  resolution: 'complete' | 'cancel',
40	  reason: string,
41	  actor: User
42	): Promise<void> {
43	  assertManagerOrAdmin(actor);
44	  if (reason.trim().length < 10) {
45	    throw new Error('ANOMALY_REASON_TOO_SHORT');
46	  }
47	
48	  const session = await db.sessions_charging.get(sessionId);
49	  if (!session || session.status !== 'Anomaly') {
50	    throw new Error('SESSION_INVALID_STATE');
51	  }
52	  assertSiteScope(actor, session.siteId);
53	
54	  if (resolution === 'complete') {
55	    await db.sessions_charging.update(sessionId, { status: 'Active' });
56	    await completeSession(sessionId, actor);
57	  } else {
58	    const now = Date.now();
59	    await db.sessions_charging.update(sessionId, {
60	      status: 'Completed',
61	      endedAt: now,
62	      anomalyReason: `${session.anomalyReason ?? ''} | cancelled: ${reason}`,
63	      version: session.version + 1
64	    });
65	    await db.reservations.update(session.reservationId, { status: 'Cancelled' });
66	    await db.bays.update(session.bayId, { status: 'Available' });
67	    await notificationService.sendTemplateToSiteStaff(session.siteId, 'HOLD_AVAILABLE', actor, {
68	      bayLabel: String(session.bayId)
69	    });
70	  }
71	
72	  await auditService.log(actor, 'ANOMALY_RESOLVED', 'ChargingSession', sessionId, {
73	    resolution,
74	    reason
75	  });
76	}
77	
78	export const sessionService = {
79	  completeSession,
80	  resolveAnomaly
81	};
